#include "interface.h"
#include <vector>
#include <algorithm>

namespace {

inline uint64_t mix(uint64_t hash, uint64_t value) {
  hash ^= value;
  hash *= 1099511628211ULL;
  return hash;
}

} // namespace

uint64_t histogram_checksum(const std::vector<uint32_t>& values, uint32_t bins, int iters) {
  // Use a vector as a direct-address table for O(1) access and better cache locality
  // Pre-allocate outside the loop to avoid repeated allocations
  std::vector<uint32_t> counts(bins, 0);
  uint64_t hash = 0;

  for (int iter = 0; iter < iters; ++iter) {
    // Efficiently clear the histogram for the next iteration
    std::fill(counts.begin(), counts.end(), 0);

    // Accumulate counts
    for (uint32_t v : values) {
      // Assuming values are within [0, bins), as per the logic of the original map-based solution
      if (v < bins) {
        ++counts[v];
      }
    }

    // Calculate checksum
    hash = 1469598103934665603ULL;
    for (uint32_t b = 0; b < bins; ++b) {
      hash = mix(hash, counts[b]);
    }
  }

  return hash;
}
